// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.joinengine;

import java.util.ArrayList;
import java.util.List;

import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.TupleExpr;

/**
 * Left-deep subset DP planner for small join regions.
 */
public final class DpSubsetPlanner implements JoinOrderPlanner {

	private static final int MAX_DP_OPERANDS = 20;

	private static final class PlanState {
		private final List<Integer> order;
		private final double cost;
		private final double cardinality;

		private PlanState(List<Integer> order, double cost, double cardinality) {
			this.order = order;
			this.cost = cost;
			this.cardinality = cardinality;
		}
	}

	@Override
	public String name() {
		return "dp-subset";
	}

	@Override
	public List<JoinOrderCandidate> generatePlans(JoinRegion region, JoinOptimizationContext ctx) {
		if (!ctx.getConfig().isEnableDp()) {
			return List.of();
		}
		List<TupleExpr> atoms = region.getAtoms();
		int n = atoms.size();
		if (n <= 2 || n > MAX_DP_OPERANDS || n > ctx.getConfig().getDpThreshold()) {
			return List.of();
		}

		int total = 1 << n;
		PlanState[] best = new PlanState[total];
		for (int i = 0; i < n; i++) {
			TupleExpr atom = atoms.get(i);
			double card = safeCardinality(ctx.getStats().getCardinality(atom));
			best[1 << i] = new PlanState(List.of(i), card, card);
		}

		for (int mask = 1; mask < total; mask++) {
			if (best[mask] != null && Integer.bitCount(mask) == 1) {
				continue;
			}
			PlanState bestState = null;
			for (int next = 0; next < n; next++) {
				int bit = 1 << next;
				if ((mask & bit) == 0) {
					continue;
				}
				int prevMask = mask ^ bit;
				if (prevMask == 0 || best[prevMask] == null) {
					continue;
				}
				PlanState previous = best[prevMask];
				List<Integer> candidateOrder = new ArrayList<>(previous.order.size() + 1);
				candidateOrder.addAll(previous.order);
				candidateOrder.add(next);
				double joinCardinality = estimateJoinCardinality(candidateOrder, atoms, ctx);
				double candidateCost = previous.cost + Math.max(1.0d, previous.cardinality) * joinCardinality;
				PlanState candidate = new PlanState(candidateOrder, candidateCost, joinCardinality);
				if (bestState == null || candidate.cost < bestState.cost
						|| (candidate.cost == bestState.cost
								&& compareLexicographic(candidate.order, bestState.order) < 0)) {
					bestState = candidate;
				}
			}
			best[mask] = bestState;
		}

		PlanState chosen = best[total - 1];
		if (chosen == null) {
			return List.of();
		}
		List<TupleExpr> order = new ArrayList<>(n);
		for (Integer index : chosen.order) {
			order.add(atoms.get(index));
		}
		return List.of(JoinOrderCandidate.of(name(), order, atoms));
	}

	private int compareLexicographic(List<Integer> left, List<Integer> right) {
		int size = Math.min(left.size(), right.size());
		for (int i = 0; i < size; i++) {
			int cmp = Integer.compare(left.get(i), right.get(i));
			if (cmp != 0) {
				return cmp;
			}
		}
		return Integer.compare(left.size(), right.size());
	}

	private double estimateJoinCardinality(List<Integer> order, List<TupleExpr> atoms, JoinOptimizationContext ctx) {
		TupleExpr join = cloneOrderAsJoin(order, atoms);
		return safeCardinality(ctx.getStats().getCardinality(join));
	}

	private TupleExpr cloneOrderAsJoin(List<Integer> order, List<TupleExpr> atoms) {
		TupleExpr current = atoms.get(order.get(0)).clone();
		for (int i = 1; i < order.size(); i++) {
			current = new Join(current, atoms.get(order.get(i)).clone());
		}
		return current;
	}

	private double safeCardinality(double value) {
		if (!Double.isFinite(value) || value < 0.0d) {
			return 1.0d;
		}
		return Math.max(1.0d, value);
	}
}
